def effective_n(x, y):
    rx, ry = lag1_autocorrelation(x), lag1_autocorrelation(y)
    return len(x) * (1 - rx * ry) / (1 + rx * ry)


def r_threshold(neff, alpha=0.05):
    dof = neff - 2
    tcrit = stats.t.ppf(1 - alpha / 2, dof)
    return np.sqrt(tcrit**2 / (tcrit**2 + dof))


